output.sparql:
PREFIX ql: <http://qlever.cs.uni-freiburg.de/builtin-functions/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?sourceCountry ?sourceCountryLabel ?mouth ?mouthLabel WHERE {
  wd:Q179396 wdt:P403 ?mouth .
  wd:Q179396 wdt:P17 ?sourceCountry .
  SERVICE <https://qlever.cs.uni-freiburg.de/builtin-functions> {
    ?mouth ql:label ?mouthLabel .
    ?sourceCountry ql:label ?sourceCountryLabel .
    FILTER(lang(?mouthLabel) = 'en' && lang(?sourceCountryLabel) = 'en')
  }
}
